    html = std::regex_replace(html, headerRegex, [](const std::smatch& m) {
        int level = m[1].length();
        return "<h" + std::to_string(level) + ">" + m[2].str() + "</h" + std::to_string(level) + ">";
    });

    // Convert bold text
    std::regex boldRegex("\\*\\*(.*?)\\*\\*");
    html = std::regex_replace(html, boldRegex, "<strong>$1</strong>");

    // Convert italic text
    std::regex italicRegex("\\*(.*?)\\*");
    html = std::regex_replace(html, italicRegex, "<em>$1</em>");

    // Convert unordered lists
    std::regex ulRegex("^-\\s*(.*)$", std::regex::multiline);
    html = std::regex_replace(html, ulRegex, "<li>$1</li>");
    std::regex ulWrapperRegex("(<li>.*?</li>)", std::regex::dotall);
    html = std::regex_replace(html, ulWrapperRegex, "<ul>$1</ul>");

    // Convert ordered lists
    std::regex olRegex("^\\d+\\.\\s*(.*)$", std::regex::multiline);
    html = std::regex_replace(html, olRegex, "<li>$1</li>");
    std::regex olWrapperRegex("(<li>.*?</li>)", std::regex::dotall);
    html = std::regex_replace(html, olWrapperRegex, "<ol>$1</ol>");

    return html;
}

