#include <string>
#include <vector>
#include <iostream>
#include <sstream>
#include <cassert>

std::string markdown_to_html(const std::string& markdown) {
    std::string html;
    std::istringstream iss(markdown);
    std::string line;

    while (std::getline(iss, line)) {
        // Headers
        if (line[0] == '#') {
            html += "<h1>" + line.substr(2) + "</h1>";
        } else {
            size_t pos = 0;
            while ((pos = line.find("**", pos)) != std::string::npos) {
                // Bold text
                html += line.substr(0, pos) + "<strong>";
                pos += 2;
                size_t end_pos = line.find("**", pos);
                if (end_pos != std::string::npos) {
                    html += line.substr(pos, end_pos - pos) + "</strong>";
                    pos = end_pos + 2;
                }
            }
            pos = 0;
            while ((pos = line.find("*", pos)) != std::string::npos) {
                // Italic text
                if (pos > 0 && line[pos - 1] != '*' && line[pos + 1] != '*') {
                    html += line.substr(0, pos) + "<em>";
                    pos++;
                    size_t end_pos = line.find("*", pos);
                    if (end_pos != std::string::npos) {
                        html += line.substr(pos, end_pos - pos) + "</em>";
                        pos = end_pos + 1;
                    }
                } else {
                    pos++;
                }
            }
            // Unordered lists
            if (line[0] == '-') {
                html += "<li>" + line.substr(2) + "</li>";
            } else {
                html += line;
            }
        }
        html += "\n";
    }
    return html;
}

void check_conversion(const std::string& markdown, const std::string& expected_html) {
    std::string result = markdown_to_html(markdown);
    assert(result == expected_html);
}

